import type { VolunteerEntry, VolunteerPlan } from '../types';

/**
 * 风险预警检查
 */
export function checkRisks(entries: VolunteerEntry[]): string[] {
  const warnings: string[] = [];

  if (entries.length === 0) {
    warnings.push('志愿表为空，请添加至少一个志愿');
    return warnings;
  }

  // 检查是否有"冲"的志愿
  const rushEntries = entries.filter((e) => e.riskLevel === 'rush');
  const stableEntries = entries.filter((e) => e.riskLevel === 'stable');
  const safeEntries = entries.filter((e) => e.riskLevel === 'safe');

  if (rushEntries.length === 0) {
    warnings.push('建议添加一些"冲"的志愿，增加上岸好学校的机会');
  }

  if (stableEntries.length === 0) {
    warnings.push('建议添加一些"稳"的志愿，确保有合适学校可上');
  }

  if (safeEntries.length === 0) {
    warnings.push('⚠️ 没有"保"的志愿，存在滑档风险！');
  }

  // 检查是否都勾选了服从调剂
  const noAdjustment = entries.filter((e) => !e.acceptAdjustment);
  if (noAdjustment.length > 0) {
    warnings.push(`${noAdjustment.length} 个志愿未勾选"服从调剂"，增加退档风险`);
  }

  // 检查重复院校
  const collegeIds = entries.map((e) => e.collegeGroupId);
  const duplicates = new Set(
    collegeIds.filter((id, idx) => collegeIds.indexOf(id) !== idx)
  );
  if (duplicates.size > 0) {
    warnings.push('存在重复的院校专业组志愿');
  }

  return warnings;
}

/**
 * 计算方案整体风险评分
 */
export function calcPlanRisk(entries: VolunteerEntry[]): {
  score: number;
  level: 'high' | 'medium' | 'low';
} {
  if (entries.length === 0) return { score: 0, level: 'high' };

  const { rush, stable, safe } = {
    rush: entries.filter((e) => e.riskLevel === 'rush').length,
    stable: entries.filter((e) => e.riskLevel === 'stable').length,
    safe: entries.filter((e) => e.riskLevel === 'safe').length,
  };

  const total = entries.length;
  let score = 60; // 基础分

  // 梯度合理加分
  if (rush > 0 && stable > 0 && safe > 0) score += 20;
  if (safe / total >= 0.3) score += 10; // 保底占30%以上

  // 不服从调剂扣分
  const noAdj = entries.filter((e) => !e.acceptAdjustment).length;
  score -= noAdj * 3;

  // 志愿数量不足扣分
  if (total < 10) score -= 10;
  if (total < 5) score -= 15;

  score = Math.max(0, Math.min(100, score));

  return {
    score,
    level: score >= 80 ? 'low' : score >= 50 ? 'medium' : 'high',
  };
}

/**
 * 序列化志愿方案
 */
export function serializePlan(plan: VolunteerPlan): string {
  return JSON.stringify(plan, null, 2);
}

/**
 * 反序列化志愿方案
 */
export function deserializePlan(json: string): VolunteerPlan {
  return JSON.parse(json) as VolunteerPlan;
}
