<template>
  <div class="volunteer-page">
    <h2>志愿方案</h2>

    <!-- 方案管理 -->
    <el-card shadow="never" class="plan-manage">
      <template #header>
        <div class="plan-header">
          <span>方案列表</span>
          <el-button type="primary" size="small" @click="showCreateDialog = true">
            <el-icon><Plus /></el-icon> 新建方案
          </el-button>
        </div>
      </template>

      <el-tabs v-model="activePlanId" type="card" closable @tab-close="handleCloseTab">
        <el-tab-pane
          v-for="plan in plans"
          :key="plan.id"
          :label="plan.name"
          :name="plan.id"
        />
      </el-tabs>
    </el-card>

    <!-- 当前方案概览 -->
    <el-card v-if="activePlan" shadow="never" class="overview-card">
      <template #header>
        <span>{{ activePlan.name }} - 概览</span>
      </template>
      <el-row :gutter="16">
        <el-col :span="6">
          <div class="overview-item">
            <div class="label">已填志愿</div>
            <div class="value">{{ activePlan.entries.length }} / 45</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="overview-item">
            <div class="label">冲</div>
            <div class="value text-rush">{{ rushCount }}</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="overview-item">
            <div class="label">稳</div>
            <div class="value text-stable">{{ stableCount }}</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="overview-item">
            <div class="label">保</div>
            <div class="value text-safe">{{ safeCount }}</div>
          </div>
        </el-col>
      </el-row>
    </el-card>

    <!-- 风险预警 -->
    <el-alert
      v-if="warnings.length > 0"
      :title="'风险预警 (' + warnings.length + ')'"
      type="warning"
      :closable="false"
      show-icon
      class="warning-card"
    >
      <template #default>
        <ul class="warning-list">
          <li v-for="(w, i) in warnings" :key="i">{{ w }}</li>
        </ul>
      </template>
    </el-alert>

    <!-- 志愿表 -->
    <el-card shadow="never" class="table-card">
      <template #header>
        <div class="table-header">
          <span>志愿表（平行志愿，最多 45 个）</span>
          <div>
            <el-button size="small" @click="exportPlan">导出 JSON</el-button>
            <el-upload
              :show-file-list="false"
              :before-upload="handleImport"
              accept=".json"
            >
              <el-button size="small">导入 JSON</el-button>
            </el-upload>
          </div>
        </div>
      </template>

      <el-table :data="entries" border stripe style="width: 100%">
        <el-table-column label="#" width="60" align="center">
          <template #default="{ $index }">{{ $index + 1 }}</template>
        </el-table-column>
        <el-table-column label="院校" min-width="160">
          <template #default="{ row }">
            <div class="entry-name">{{ row.collegeName }}</div>
            <div class="entry-group">{{ row.groupName }}</div>
          </template>
        </el-table-column>
        <el-table-column label="风险" width="80" align="center">
          <template #default="{ row }">
            <el-tag :type="riskTagType(row.riskLevel)" size="small">
              {{ riskLabel(row.riskLevel) }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column label="专业选择" min-width="200">
          <template #default="{ row }">
            <div v-if="row.selectedMajors.length > 0" class="majors">
              <el-tag v-for="(m, i) in row.selectedMajors.slice(0, 3)" :key="i" size="small">
                {{ m }}
              </el-tag>
              <span v-if="row.selectedMajors.length > 3">等{{ row.selectedMajors.length }}个</span>
            </div>
            <span v-else class="empty-text">未选择</span>
          </template>
        </el-table-column>
        <el-table-column label="服从调剂" width="100" align="center">
          <template #default="{ row }">
            <el-switch
              v-model="row.acceptAdjustment"
              size="small"
              @change="onAdjustmentChange(row)"
            />
          </template>
        </el-table-column>
        <el-table-column label="备注" min-width="120">
          <template #default="{ row }">
            <el-input v-model="row.remark" size="small" placeholder="" />
          </template>
        </el-table-column>
        <el-table-column label="操作" width="80" align="center">
          <template #default="{ row, $index }">
            <el-popconfirm title="确定删除?" @confirm="handleDelete($index)">
              <template #reference>
                <el-button link type="danger" size="small">删除</el-button>
              </template>
            </el-popconfirm>
          </template>
        </el-table-column>
      </el-table>
    </el-card>

    <!-- 新建方案对话框 -->
    <el-dialog v-model="showCreateDialog" title="新建志愿方案" width="500px">
      <el-form :model="newPlanForm" label-width="80px">
        <el-form-item label="方案名称">
          <el-input v-model="newPlanForm.name" placeholder="如：2026年物理类方案" />
        </el-form-item>
        <el-form-item label="科类">
          <el-radio-group v-model="newPlanForm.category">
            <el-radio-button value="physical">物理类</el-radio-button>
            <el-radio-button value="history">历史类</el-radio-button>
          </el-radio-group>
        </el-form-item>
      </el-form>
      <template #footer>
        <el-button @click="showCreateDialog = false">取消</el-button>
        <el-button type="primary" @click="createPlan">创建</el-button>
      </template>
    </el-dialog>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from 'vue';
import { ElMessage } from 'element-plus';
import { usePlanStore } from '@/stores/plans';
import type { VolunteerEntry, VolunteerPlan, RiskLevel } from '@ga/shared/types';
import { checkRisks } from '@ga/shared/recommend';

const planStore = usePlanStore();

const showCreateDialog = ref(false);
const newPlanForm = ref({
  name: '',
  category: 'physical' as 'physical' | 'history',
});

const plans = computed(() => planStore.plans);
const activePlanId = computed({
  get: () => planStore.activePlanId,
  set: (val: string) => planStore.setActivePlan(val),
});

const activePlan = computed(() => planStore.activePlan);

const entries = computed(() => activePlan.value?.entries ?? []);

const rushCount = computed(() => entries.value.filter((e) => e.riskLevel === 'rush').length);
const stableCount = computed(() => entries.value.filter((e) => e.riskLevel === 'stable').length);
const safeCount = computed(() => entries.value.filter((e) => e.riskLevel === 'safe').length);

const warnings = computed(() => checkRisks(entries.value));

function riskTagType(level: RiskLevel): 'danger' | 'warning' | 'success' {
  return level === 'rush' ? 'danger' : level === 'stable' ? 'warning' : 'success';
}

function riskLabel(level: RiskLevel): string {
  return level === 'rush' ? '冲' : level === 'stable' ? '稳' : '保';
}

function createPlan() {
  if (!newPlanForm.value.name) {
    ElMessage.warning('请输入方案名称');
    return;
  }
  planStore.createPlan(newPlanForm.value.name, {
    province: '河北省',
    selectMode: '3+1+2',
    category: newPlanForm.value.category,
    score: 0,
    position: 0,
    preferences: {},
  });
  showCreateDialog.value = false;
  ElMessage.success('方案创建成功');
}

function handleCloseTab(id: string) {
  planStore.deletePlan(id);
  ElMessage.success('方案已删除');
}

function handleDelete(index: number) {
  const entry = entries.value[index];
  if (entry) {
    planStore.removeEntry(entry.id);
  }
}

function onAdjustmentChange(entry: VolunteerEntry) {
  planStore.updateEntry(entry.id, { acceptAdjustment: entry.acceptAdjustment });
}

function exportPlan() {
  if (!activePlanId.value) return;
  const json = planStore.exportPlan(activePlanId.value);
  const blob = new Blob([json], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${activePlan.value?.name || 'volunteer'}_plan.json`;
  a.click();
  URL.revokeObjectURL(url);
}

function handleImport(file: File) {
  const reader = new FileReader();
  reader.onload = (e) => {
    const text = e.target?.result as string;
    if (planStore.importPlan(text)) {
      ElMessage.success('导入成功');
    } else {
      ElMessage.error('导入失败，文件格式不正确');
    }
  };
  reader.readAsText(file);
  return false;
}
</script>

