import { defineStore } from 'pinia';
import type { VolunteerPlan, VolunteerEntry } from '@ga/shared/types';

export const usePlanStore = defineStore('plans', {
  state: () => ({
    plans: [] as VolunteerPlan[],
    activePlanId: '' as string,
  }),

  getters: {
    activePlan: (state) =>
      state.plans.find((p) => p.id === state.activePlanId),
    favoritePlans: (state) =>
      state.plans.filter((p) => p.isFavorite),
  },

  actions: {
    createPlan(name: string, userInput: VolunteerPlan['userInput']): string {
      const id = `plan_${Date.now()}`;
      const now = new Date().toISOString();
      const plan: VolunteerPlan = {
        id,
        name,
        createdAt: now,
        updatedAt: now,
        userInput,
        entries: [],
      };
      this.plans.push(plan);
      this.activePlanId = id;
      return id;
    },

    addEntry(entry: VolunteerEntry) {
      const plan = this.plans.find((p) => p.id === this.activePlanId);
      if (!plan) return;
      plan.entries.push(entry);
      plan.updatedAt = new Date().toISOString();
    },

    removeEntry(entryId: string) {
      const plan = this.plans.find((p) => p.id === this.activePlanId);
      if (!plan) return;
      plan.entries = plan.entries.filter((e) => e.id !== entryId);
      plan.updatedAt = new Date().toISOString();
    },

    updateEntry(entryId: string, updates: Partial<VolunteerEntry>) {
      const plan = this.plans.find((p) => p.id === this.activePlanId);
      if (!plan) return;
      const entry = plan.entries.find((e) => e.id === entryId);
      if (entry) {
        Object.assign(entry, updates);
        plan.updatedAt = new Date().toISOString();
      }
    },

    setActivePlan(id: string) {
      this.activePlanId = id;
    },

    deletePlan(id: string) {
      this.plans = this.plans.filter((p) => p.id !== id);
      if (this.activePlanId === id) {
        this.activePlanId = this.plans[0]?.id ?? '';
      }
    },

    exportPlan(planId: string): string {
      const plan = this.plans.find((p) => p.id === planId);
      return plan ? JSON.stringify(plan, null, 2) : '';
    },

    importPlan(json: string) {
      try {
        const plan = JSON.parse(json) as VolunteerPlan;
        plan.id = `plan_${Date.now()}`;
        plan.createdAt = new Date().toISOString();
        plan.updatedAt = new Date().toISOString();
        this.plans.push(plan);
        return true;
      } catch {
        return false;
      }
    },
  },
});
